from collections import defaultdict

def solve(jobs: list[list[dict]]) -> list[list[dict]]:
    if not jobs:
        return []

    num_jobs = len(jobs)
    num_machines = max(op["machine"] for job in jobs for op in job) + 1

    # Initialize start times for all operations to 0
    for job in jobs:
        for op in job:
            op["start"] = 0

    # Create a list of machines and their operations
    machine_operations = defaultdict(list)
    for job_idx, job in enumerate(jobs):
        for op in job:
            machine_operations[op["machine"]].append((job_idx, op))

    # Function to compute the makespan
    def compute_makespan():
        max_end = 0
        for job in jobs:
            end_time = 0
            for op in job:
                end_time = max(end_time, op["start"]) + op["duration"]
                op["start"] = max(op["start"], end_time - op["duration"])
            max_end = max(max_end, end_time)
        return max_end

    # Function to solve the single-machine scheduling problem for a given machine
    def solve_single_machine(machine):
        operations = machine_operations[machine]
        job_indices = [job_idx for job_idx, _ in operations]
        durations = [op["duration"] for _, op in operations]

        # Create a list of (release_time, job_idx, duration)
        release_times = []
        for job_idx in job_indices:
            job = jobs[job_idx]
            release_time = 0
            for op in job:
                if op["machine"] == machine:
                    break
                release_time = max(release_time, op["start"]) + op["duration"]
            release_times.append((release_time, job_idx, durations[job_indices.index(job_idx)]))

        # Sort by release time
        release_times.sort()

        # Schedule operations in order of release time
        current_time = 0
        for release_time, job_idx, duration in release_times:
            start_time = max(current_time, release_time)
            # Find the operation in the job and update its start time
            for op in jobs[job_idx]:
                if op["machine"] == machine:
                    op["start"] = start_time
                    break
            current_time = start_time + duration

    # Main SBH loop
    for _ in range(num_machines):
        # Identify the bottleneck machine (the one with the highest load)
        machine_loads = []
        for machine in range(num_machines):
            total_duration = sum(op["duration"] for _, op in machine_operations[machine])
            machine_loads.append((total_duration, machine))
        machine_loads.sort(reverse=True)

        for _, machine in machine_loads:
            solve_single_machine(machine)

    # Final pass to ensure all constraints are met
    for job in jobs:
        current_time = 0
        for op in job:
            op["start"] = max(op["start"], current_time)
            current_time = op["start"] + op["duration"]

    return jobs
